// =========================
// ⚙️ CONFIGURACIÃN — edita solo esto
// =========================
const SHOP_EMAIL = 'taller@ejemplo.com'; // ← pon aquí el email del taller

const body = $json.body || $json || {};

// =========================
// SOPORTE DOBLE FORMATO
// - Si el body trae "data.fields" (formularios tipo Tally)
// - Si el body es plano (nuestra landing: name, phone, vehicle, service, detail...)
// =========================
const fields = body?.data?.fields;

const getField = (label) =>
  (fields || []).find(f => (f.label || '').toLowerCase().includes(label.toLowerCase()));
const getText = (label) => getField(label)?.value ?? null;
const getDropdownText = (field) => {
  if (!field?.value?.length) return null;
  const selected = field.options?.find(o => o.id === field.value[0]);
  return selected?.text || null;
};
const getCheckboxValues = (field) => {
  if (!field) return [];
  if (Array.isArray(field.value)) {
    return (field.options || []).filter(o => field.value.includes(o.id)).map(o => o.text);
  }
  if (typeof field.value === 'boolean' && field.value === true) {
    const match = (field.label || '').match(/\((.*?)\)/);
    return match ? [match[1]] : [];
  }
  return [];
};

let nombre, telefono, instagram, vehiculo, servicio, mensaje, taller, pais;

if (Array.isArray(fields)) {
  nombre = getText('Nombre completo');
  telefono = getText('Numero de telefono');
  instagram = getText('Instagram');
  vehiculo = getText('Que coche tienes');
  pais = getText('De donde eres');
  mensaje = getText('importante');
  servicio = getCheckboxValues(getField('Que te gustaria hacer')).join(', ');
  taller = '';
} else {
  nombre = body.name || 'Cliente demo';
  telefono = body.phone || '';
  instagram = body.instagram || '';
  vehiculo = body.vehicle || '—';
  servicio = body.service || 'Consulta';
  mensaje = body.detail || body.message || '';
  taller = body.shop || '';
  pais = body.pais || body.location || '';
}

// =========================
// SCORE 0-100
// =========================
let score = 0;

// 🔧 SERVICIO (max 35)
const hot = ['Swap', 'Electrónica', 'Competición'];
const mid = ['Preparación', 'Escape', 'Reprogramación'];
if (hot.some(s => servicio.includes(s))) score += 35;
else if (mid.some(s => servicio.includes(s))) score += 20;
else score += 8;

// 📱 TELÉFONO VÁLIDO (max 20)
const digits = (telefono || '').replace(/\D/g, '');
score += digits.length >= 9 ? 20 : 5;

// ⏱️ URGENCIA / PALABRAS CLAVE EN EL MENSAJE (max 25)
const msg = (mensaje || '').toLowerCase();
const urgentWords = ['presupuesto', 'precio', 'cuanto', 'cuánto', 'fecha', 'urgente'];
score += urgentWords.some(w => msg.includes(w)) ? 25 : 10;

// 🧠 CLARIDAD DEL MENSAJE (max 20)
const wordCount = msg.split(/\s+/).filter(Boolean).length;
if (wordCount > 15) score += 20;
else if (wordCount >= 5) score += 12;
else score += 4;

const normalizedScore = Math.min(100, Math.round(score));

// =========================
// TEMPERATURA Y PRIORIDAD
// =========================
let leadType = '🧊 FRÍO';
if (normalizedScore >= 70) leadType = '🔥 CALIENTE';
else if (normalizedScore >= 40) leadType = '🌤️ TEMPLADO';

let priority = normalizedScore >= 70
  ? '🔥 CONTACTAR YA (<2H)'
  : normalizedScore >= 40
  ? '🌤️ CONTACTAR EN 24H'
  : '🧊 SEGUIMIENTO AUTOMÁTICO';

const whatsappDigits = (telefono || '').replace(/\D/g, '');
const whatsapp_link = normalizedScore >= 70 && whatsappDigits ? `https://wa.me/${whatsappDigits}` : '';

return [{
  json: {
    nombre, telefono, instagram, vehiculo, servicio, mensaje, taller, pais,
    score: normalizedScore,
    leadType,
    priority,
    whatsapp_link,
    shopEmail: SHOP_EMAIL,
    estado: 'Nuevo',
    fecha: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' }),
    raw: body,
  }
}];
